{
  "name": "Wyoming Energy Assistance (LIHEAP)",
  "eligibility": {
    "age": null,
    "income_limits": "Gross monthly household income at or below 60% of Wyoming state median income: 1 person $2,985; 2 people $3,904; 3 people $4,823; 4 people $5,741; 5 people $6,660; 6 people $7,579. Annual examples: 2-person household ≤$46,000; 4-person household ≤$68,902. SSI/SNAP recipients may qualify automatically. Elderly (60+), disabled, or households with children under 6 receive priority.",
    "asset_limits": "No asset limits mentioned in program sources.",
    "other_requirements": ["Must be responsible for home energy costs (homeowners, renters, permanently parked RVs).", "Wyoming resident.", "Household includes all at address sharing utility bill."]
  },
  "benefits": {
    "type": "financial",
    "value": "Heating assistance: one-time payment to utility/vendor, minimum $49, maximum $2,176 per season. Crisis assistance: up to $550 for emergencies like shutoff, broken heater, or empty fuel tank. Covers primary heating fuels (propane, pellets, wood, heating oil, coal, utilities). Not full coverage of energy costs.",
    "varies_by": "household_size|income|fuel_type|priority_tier"
  },
  "application": {
    "methods": ["Online: lieapwyo.org", "Phone: 1-800-246-4221 (callback system holds place in line)", "Local: Community Action Agency, Area Agency on Aging, or state LIHEAP office (phone/mail/in-person for elderly/disabled)"],
    "processing_time": "Payments start Oct. 1 for crisis cases; others after Oct. 1. No specific processing days stated.",
    "waitlist": "Higher-than-normal applications reported; phone callback system manages demand.",
    "forms": ["No specific form name/number listed; apply via website/phone/local agency"],
    "documents": ["Proof of identity", "Proof of income for all household members", "Recent utility bill", "Social Security numbers for household members", "Proof of U.S. citizenship or eligible immigration status"]
  },
  "geography": {
    "statewide": true,
    "restrictions": "None; covers all Wyoming households (homeowners/renters/RVs)",
    "regional_variations": "Administered statewide by Wyoming Department of Family Services; eligibility determined by contractor NOWCAP. Local agencies handle applications with potential regional wait variations due to demand.",
    "offices_or_providers": ["Wyoming Department of Family Services", "NOWCAP (eligibility contractor)", "Local Community Action Agencies", "Area Agencies on Aging"]
  },
  "official_source": "https://dfs.wyo.gov/assistance-programs/home-utilities-energy-assistance/",
  "gotchas": ["Priority for elderly 60+ and crisis cases until Oct. 1; general applications Oct. 1-April 30 only.", "No cooling assistance.", "Household counts all at address on utility bill (differs from SNAP).", "High application volume; use callback phone feature.", "Covers heating fuels/utilities directly; not full bill payment.", "2025-2026 season applications open until April 30, 2026."],
  "data_shape_notes": "Income at 60% state median (higher than federal 150% FPL in WY); priority tiers for elderly/disabled/young children/crisis; statewide but local agency delivery; heating-season only (Oct-April); varies by fuel type and crisis status."
}

{
  "name": "Legal Assistance for Seniors (via Wyoming Legal Services)",
  "eligibility": {
    "age": 60,
    "income_limits": "Low-income requirements based on federal poverty guidelines; exact dollar amounts and household size table not specified in sources—must apply to confirm. Providers like Legal Aid of Wyoming assess income, assets, citizenship, and other factors via WYLawHelp screener.[6][8]",
    "asset_limits": "Assets considered for eligibility in related elder law services (e.g., Medicaid planning), with limits like $2,000 for long-term care applicants (exceptions apply); specific counts/exemptions for Legal Aid not detailed—primary residence, vehicle may be exempt in similar programs.[5]",
    "other_requirements": ["Low-income status", "Wyoming resident", "Civil legal issue in priority areas like elder law, public benefits, housing, domestic violence", "Case acceptance guidelines per provider"]
  },
  "benefits": {
    "type": "service",
    "value": "Free civil legal assistance including advice, representation in elder law, public benefits, housing, education, health care access, employment, domestic violence; may include simple wills, powers of attorney, advanced directives via related programs like Estate Planning Practicum.[6][8][9]",
    "varies_by": "priority_tier"
  },
  "application": {
    "methods": ["Online via https://www.lawyoming.org (Legal Aid of Wyoming apply now)", "WYLawHelp.org for eligibility screening and provider contacts[6]", "Phone: Contact Legal Aid of Wyoming (number via site) or Wyoming State Bar Modest Means at (307) 766-6416 for related services[6]", "Download/print Modest Means Program Client Application and mail to Wyoming State Bar[6]", "In-person via local offices (e.g., Albany County resources)"],
    "processing_time": "Not specified",
    "waitlist": null,
    "forms": ["Modest Means Program Client Application (Wyoming State Bar)[6]", "Legal Aid of Wyoming online application[8]"],
    "documents": ["Proof of income, household size, assets, citizenship/residency, details of legal issue; specific list confirmed upon application[6]"]
  },
  "geography": {
    "statewide": true,
    "restrictions": null,
    "regional_variations": "Services via Legal Aid of Wyoming statewide, but related senior programs (e.g., caregiver support) limited to counties like Albany, Fremont, Park; county public health offices handle assessments for linked services like LT101[2][4]",
    "offices_or_providers": ["Legal Aid of Wyoming (statewide non-profit)[8]", "Wyoming State Bar Modest Means Program (statewide)[6]", "Estate Planning Practicum (307) 766-6416[6]"]
  },
  "official_source": "https://www.lawyoming.org",
  "gotchas": ["Must apply directly with providers like Legal Aid of Wyoming to confirm eligibility—screeners like WYLawHelp provide estimates only[6]", "Not all cases accepted; priority on civil matters, no criminal or fee-generating cases[8]", "Modest Means is reduced fee ($100/hr max, $1,000 retainer), not free—only for those above free legal aid thresholds[6]", "Funds restricted by Legal Services Corporation rules, cannot assist certain immigration/fee cases[8]"],
  "data_shape_notes": "Eligibility via multiple providers (Legal Aid of Wyoming primary for free services, State Bar for modest means); no fixed income/asset tables published—case-by-case with federal poverty tie-in; priority-based case acceptance"
}
